import ExcelJS from "exceljs";
import { saveAs } from "file-saver";

export const BEEFAST_LOGO_BASE64 =
  "";

function colNumToName(num) {
  let s = "";
  while (num > 0) {
    let mod = (num - 1) % 26;
    s = String.fromCharCode(65 + mod) + s;
    num = Math.floor((num - mod) / 26);
  }
  return s;
}

export async function exportExcelTemplate({
  title = "ATTENDANCE REPORT",
  sheetName = "Report",
  columns = [],
  data = [],
  appName = "BEEFAST",
  companyName = "PT Aplikanusa Lintasarta",
  exportedBy = "Admin",
  logoBase64 = BEEFAST_LOGO_BASE64,
}) {
  if (!data.length) {
    alert("Tidak ada data untuk diekspor.");
    return;
  }

  const workbook = new ExcelJS.Workbook();
  const sheet = workbook.addWorksheet(sheetName);
  const today = new Date().toLocaleDateString("id-ID");
  const lastCol = colNumToName(columns.length);

  if (logoBase64) {
    const logoId = workbook.addImage({
      base64: logoBase64,
      extension: "png",
    });

    sheet.addImage(logoId, {
      tl: { col: 0, row: 0 },
      ext: { width: 70, height: 70 },
    });
  }

  sheet.mergeCells(`B1:${lastCol}1`);
  sheet.getCell("B1").value = appName;
  sheet.getCell("B1").font = { bold: true, size: 16 };
  sheet.getCell("B1").alignment = { vertical: "middle" };

  sheet.mergeCells(`B2:${lastCol}2`);
  sheet.getCell("B2").value = companyName;
  sheet.getCell("B2").font = { size: 11 };
  sheet.getCell("B2").alignment = { vertical: "middle" };

  sheet.mergeCells(`B3:${lastCol}3`);
  sheet.getCell("B3").value = `Tanggal Export: ${today}`;
  sheet.getCell("B3").font = { size: 10, italic: true };
  sheet.getCell("B3").alignment = { vertical: "middle" };

  sheet.mergeCells(`A4:${lastCol}4`);
  sheet.getCell("A4").border = {
    bottom: { style: "medium" },
  };

  sheet.mergeCells(`A6:${lastCol}6`);
  sheet.getCell("A6").value = title;
  sheet.getCell("A6").font = { bold: true, size: 14 };
  sheet.getCell("A6").alignment = { horizontal: "center" };

  const headerRowIndex = 8;
  const firstDataRowIndex = headerRowIndex + 1;

  sheet.columns = columns;

  // column width
  columns.forEach((col, i) => {
    sheet.getColumn(i + 1).width = col.width || 20;
  });

  const headerRow = sheet.getRow(headerRowIndex);
  headerRow.values = columns.map(c => c.header);
  headerRow.height = 26;

  headerRow.eachCell(cell => {
    cell.font = { bold: true, color: { argb: "FFFFFFFF" } };
    cell.alignment = { horizontal: "center", vertical: "middle", wrapText: true };
    cell.fill = {
      type: "pattern",
      pattern: "solid",
      fgColor: { argb: "FF334155" }, // slate-700
    };
    cell.border = {
      top: { style: "thin" },
      bottom: { style: "thin" },
      left: { style: "thin" },
      right: { style: "thin" },
    };
  });

  data.forEach((obj, idx) => {
    const row = sheet.getRow(firstDataRowIndex + idx);

    row.values = columns.map(col =>
      col.key === "no" ? idx + 1 : obj[col.key] ?? ""
    );

    row.height = 22;

    row.eachCell(cell => {
      cell.border = {
        top: { style: "thin" },
        bottom: { style: "thin" },
        left: { style: "thin" },
        right: { style: "thin" },
      };
      cell.alignment = { vertical: "middle" };
    });
  });

  sheet.views = [{ state: "frozen", ySplit: headerRowIndex }];
  sheet.autoFilter = `A${headerRowIndex}:${lastCol}${headerRowIndex}`;

  const footerStart = firstDataRowIndex + data.length + 4;

  sheet.mergeCells(`A${footerStart}:${lastCol}${footerStart}`);
  sheet.getCell(`A${footerStart}`).value = `Jakarta, ${today}`;
  sheet.getCell(`A${footerStart}`).alignment = { horizontal: "right" };

  sheet.mergeCells(`A${footerStart + 2}:${lastCol}${footerStart + 2}`);
  sheet.getCell(`A${footerStart + 2}`).value = "Diekspor oleh,";
  sheet.getCell(`A${footerStart + 2}`).alignment = { horizontal: "right" };

  sheet.mergeCells(`A${footerStart + 5}:${lastCol}${footerStart + 5}`);
  sheet.getCell(`A${footerStart + 5}`).value = exportedBy;
  sheet.getCell(`A${footerStart + 5}`).font = { bold: true };
  sheet.getCell(`A${footerStart + 5}`).alignment = { horizontal: "right" };

  const buf = await workbook.xlsx.writeBuffer();
  saveAs(
    new Blob([buf]),
    `${title.replace(/\s+/g, "_")}_${today.replace(/\//g, "-")}.xlsx`
  );
}
